42	export const processScenario = (scenario: any): any => {
43	  const results = scenario.steps.map((step: any) => {
44	    const mainItems = step.items.filter(isMainItem);
45	    const components = step.items.filter((item: any) => !isMainItem(item));
46	
47	    const mainTotal = mainItems.reduce(
48	      (sum: number, item: any) => {
49	        const base = premiumForType(item.type);
50	        const cursedSurcharge = item.cursed ? base * 0.5 : 0;
51	        const enchantmentSurcharge = item.enchantment >= 5 ? base * 0.3 : 0;
52	        return sum + base + cursedSurcharge + enchantmentSurcharge;
53	      },
54	      0,
55	    );
56	
57	    const componentTotal = calculateComponentPremium(components);
58	
59	    const premium = mainTotal + componentTotal + PROCESSING_FEE;
60	    return { premium };
61	  });
62	  return { results };
63	};
